import InputParser from '../src/parser/InputParser.js';

describe('InputParser', () => {
  let parser;

  beforeEach(() => {
    parser = new InputParser();
  });

  describe('constructor', () => {
    it('should initialize with supported commands', () => {
      expect(parser.supportedCommands).toBeDefined();
      expect(parser.supportedCommands).toContain('help');
      expect(parser.supportedCommands).toContain('clear');
    });

    it('should initialize regex patterns', () => {
      expect(parser.mentionPattern).toBeDefined();
      expect(parser.commandPattern).toBeDefined();
    });
  });

  describe('extractMentions', () => {
    it('should extract single file mention', () => {
      const mentions = parser.extractMentions('Check @file.js');
      expect(mentions).toEqual(['file.js']);
    });

    it('should extract multiple file mentions', () => {
      const mentions = parser.extractMentions('Check @file1.js and @file2.js');
      expect(mentions).toEqual(['file1.js', 'file2.js']);
    });

    it('should extract mentions with paths', () => {
      const mentions = parser.extractMentions('Look at @src/index.js');
      expect(mentions).toEqual(['src/index.js']);
    });

    it('should extract quoted mentions with spaces', () => {
      const mentions = parser.extractMentions('Check @"my file.js"');
      expect(mentions).toEqual(['my file.js']);
    });

    it('should extract single-quoted mentions', () => {
      const mentions = parser.extractMentions("Check @'my file.js'");
      expect(mentions).toEqual(['my file.js']);
    });

    it('should extract mixed quoted and unquoted mentions', () => {
      const mentions = parser.extractMentions('@file1.js @"file 2.js" @file3.js');
      expect(mentions).toEqual(['file1.js', 'file 2.js', 'file3.js']);
    });

    it('should handle mentions at start of input', () => {
      const mentions = parser.extractMentions('@file.js is important');
      expect(mentions).toEqual(['file.js']);
    });

    it('should handle mentions at end of input', () => {
      const mentions = parser.extractMentions('Check this @file.js');
      expect(mentions).toEqual(['file.js']);
    });

    it('should return empty array for no mentions', () => {
      const mentions = parser.extractMentions('No mentions here');
      expect(mentions).toEqual([]);
    });

    it('should return empty array for null input', () => {
      const mentions = parser.extractMentions(null);
      expect(mentions).toEqual([]);
    });

    it('should return empty array for undefined input', () => {
      const mentions = parser.extractMentions(undefined);
      expect(mentions).toEqual([]);
    });

    it('should return empty array for empty string', () => {
      const mentions = parser.extractMentions('');
      expect(mentions).toEqual([]);
    });

    it('should handle mentions with complex paths', () => {
      const mentions = parser.extractMentions('@src/components/Button/index.js');
      expect(mentions).toEqual(['src/components/Button/index.js']);
    });

    it('should handle mentions with file extensions', () => {
      const mentions = parser.extractMentions('@file.test.js @config.json @style.css');
      expect(mentions).toEqual(['file.test.js', 'config.json', 'style.css']);
    });

    it('should not extract @ symbols that are not mentions', () => {
      const mentions = parser.extractMentions('Email me @ example.com');
      // The @ symbol with space after it won't match our pattern
      expect(mentions).toEqual([]);
    });
  });

  describe('extractCommands', () => {
    it('should extract simple command', () => {
      const command = parser.extractCommands('/help');
      expect(command).toEqual({
        name: 'help',
        args: '',
        isSupported: true
      });
    });

    it('should extract command with arguments', () => {
      const command = parser.extractCommands('/search pattern');
      expect(command).toEqual({
        name: 'search',
        args: 'pattern',
        isSupported: true
      });
    });

    it('should extract command with multiple arguments', () => {
      const command = parser.extractCommands('/set apiKey YOUR_KEY_HERE');
      expect(command).toEqual({
        name: 'set',
        args: 'apiKey YOUR_KEY_HERE',
        isSupported: true
      });
    });

    it('should handle command with leading/trailing spaces', () => {
      const command = parser.extractCommands('  /help  ');
      expect(command).toEqual({
        name: 'help',
        args: '',
        isSupported: true
      });
    });

    it('should return null for non-command input', () => {
      const command = parser.extractCommands('This is not a command');
      expect(command).toBeNull();
    });

    it('should return null for empty input', () => {
      const command = parser.extractCommands('');
      expect(command).toBeNull();
    });

    it('should return null for null input', () => {
      const command = parser.extractCommands(null);
      expect(command).toBeNull();
    });

    it('should mark unsupported commands', () => {
      const command = parser.extractCommands('/unsupported');
      expect(command).toEqual({
        name: 'unsupported',
        args: '',
        isSupported: false
      });
    });

    it('should handle all supported commands', () => {
      const commands = ['help', 'clear', 'search', 'files', 'config', 'setup', 'set', 'mode', 'tools'];
      
      commands.forEach(cmd => {
        const command = parser.extractCommands(`/${cmd}`);
        expect(command.name).toBe(cmd);
        expect(command.isSupported).toBe(true);
      });
    });

    it('should be case insensitive for command names', () => {
      const command = parser.extractCommands('/HELP');
      expect(command.name).toBe('help');
      expect(command.isSupported).toBe(true);
    });

    it('should not extract command in middle of text', () => {
      const command = parser.extractCommands('This /help is not a command');
      expect(command).toBeNull();
    });
  });

  describe('sanitizeInput', () => {
    it('should trim whitespace', () => {
      const sanitized = parser.sanitizeInput('  hello world  ');
      expect(sanitized).toBe('hello world');
    });

    it('should normalize multiple spaces', () => {
      const sanitized = parser.sanitizeInput('hello    world');
      expect(sanitized).toBe('hello world');
    });

    it('should preserve newlines', () => {
      const sanitized = parser.sanitizeInput('line1\nline2\nline3');
      expect(sanitized).toBe('line1\nline2\nline3');
    });

    it('should remove null bytes', () => {
      const sanitized = parser.sanitizeInput('hello\0world');
      expect(sanitized).toBe('helloworld');
    });

    it('should remove control characters', () => {
      const sanitized = parser.sanitizeInput('hello\x01\x02world');
      expect(sanitized).toBe('helloworld');
    });

    it('should normalize tabs to spaces', () => {
      const sanitized = parser.sanitizeInput('hello\tworld');
      // Tabs are normalized to single space for consistency
      expect(sanitized).toBe('hello world');
    });

    it('should return empty string for null input', () => {
      const sanitized = parser.sanitizeInput(null);
      expect(sanitized).toBe('');
    });

    it('should return empty string for undefined input', () => {
      const sanitized = parser.sanitizeInput(undefined);
      expect(sanitized).toBe('');
    });

    it('should return empty string for empty input', () => {
      const sanitized = parser.sanitizeInput('');
      expect(sanitized).toBe('');
    });

    it('should handle mixed whitespace', () => {
      const sanitized = parser.sanitizeInput('  hello   \n  world  ');
      // Spaces around newlines are preserved, but multiple spaces become single
      expect(sanitized).toBe('hello \n world');
    });
  });

  describe('parse', () => {
    it('should parse input with mentions', () => {
      const result = parser.parse('Check @file.js please');
      expect(result.original).toBe('Check @file.js please');
      expect(result.mentions).toEqual(['file.js']);
      expect(result.command).toBeNull();
      expect(result.isCommand).toBe(false);
    });

    it('should parse command input', () => {
      const result = parser.parse('/help');
      expect(result.original).toBe('/help');
      expect(result.mentions).toEqual([]);
      expect(result.command).toEqual({
        name: 'help',
        args: '',
        isSupported: true
      });
      expect(result.isCommand).toBe(true);
    });

    it('should parse input with both mentions and text', () => {
      const result = parser.parse('Can you review @src/index.js and @test.js?');
      expect(result.mentions).toEqual(['src/index.js', 'test.js']);
      expect(result.command).toBeNull();
      expect(result.isCommand).toBe(false);
    });

    it('should sanitize input', () => {
      const result = parser.parse('  hello   world  ');
      expect(result.sanitized).toBe('hello world');
    });

    it('should handle empty input', () => {
      const result = parser.parse('');
      expect(result.original).toBe('');
      expect(result.sanitized).toBe('');
      expect(result.mentions).toEqual([]);
      expect(result.command).toBeNull();
      expect(result.isCommand).toBe(false);
    });

    it('should handle null input', () => {
      const result = parser.parse(null);
      expect(result.original).toBe('');
      expect(result.sanitized).toBe('');
      expect(result.mentions).toEqual([]);
      expect(result.command).toBeNull();
      expect(result.isCommand).toBe(false);
    });
  });

  describe('hasMentions', () => {
    it('should return true when mentions exist', () => {
      expect(parser.hasMentions('@file.js')).toBe(true);
    });

    it('should return false when no mentions exist', () => {
      expect(parser.hasMentions('no mentions')).toBe(false);
    });

    it('should return false for empty input', () => {
      expect(parser.hasMentions('')).toBe(false);
    });
  });

  describe('isCommand', () => {
    it('should return true for valid command', () => {
      expect(parser.isCommand('/help')).toBe(true);
    });

    it('should return false for non-command', () => {
      expect(parser.isCommand('not a command')).toBe(false);
    });

    it('should return false for empty input', () => {
      expect(parser.isCommand('')).toBe(false);
    });
  });

  describe('removeMentions', () => {
    it('should remove single mention', () => {
      const result = parser.removeMentions('Check @file.js please');
      expect(result).toBe('Check please');
    });

    it('should remove multiple mentions', () => {
      const result = parser.removeMentions('Check @file1.js and @file2.js');
      expect(result).toBe('Check and');
    });

    it('should remove quoted mentions', () => {
      const result = parser.removeMentions('Check @"my file.js" please');
      expect(result).toBe('Check please');
    });

    it('should return original text when no mentions', () => {
      const result = parser.removeMentions('No mentions here');
      expect(result).toBe('No mentions here');
    });

    it('should return empty string for null input', () => {
      const result = parser.removeMentions(null);
      expect(result).toBe('');
    });

    it('should trim result', () => {
      const result = parser.removeMentions('@file.js');
      expect(result).toBe('');
    });
  });
});
